/**
 * Integration tests for the full notification pipeline.
 *
 * Tests the end-to-end flow: EventBus → NotificationService → Adapters → History,
 * with preferences controlling per-channel delivery.
 *
 * Unlike unit tests that mock dependencies, these tests wire up all real components
 * and verify the pipeline works as a whole.
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
import { EmailNotificationAdapter } from '../../src/adapters/email.adapter.js';
import { SmsNotificationAdapter } from '../../src/adapters/sms.adapter.js';
import { WebhookNotificationAdapter } from '../../src/adapters/webhook.adapter.js';
import { PreferencesService, resetPreferencesIdCounter } from '../../src/services/preferences.service.js';
import { NotificationHistoryService, resetNotificationLogIdCounter } from '../../src/services/notification-history.service.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { Database } from '../../src/utils/database.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, UserCreatedEvent, UserUpdatedEvent } from '../../src/events/event-types.js';
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';
import type { SentEmailRecord } from '../../src/adapters/email.adapter.js';
import type { SentSmsRecord } from '../../src/adapters/sms.adapter.js';
import type { SentWebhookRecord } from '../../src/adapters/webhook.adapter.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeUser(overrides?: Partial<User>): User {
  return {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

function makeOrder(overrides?: Partial<Order>): Order {
  return {
    id: 'order-1',
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
    total: 20,
    status: 'pending',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

// ---------------------------------------------------------------------------
// Full pipeline setup
// ---------------------------------------------------------------------------

interface Pipeline {
  db: Database;
  eventBus: EventBus;
  notificationService: NotificationService;
  emailAdapter: EmailNotificationAdapter;
  smsAdapter: SmsNotificationAdapter;
  webhookAdapter: WebhookNotificationAdapter;
  preferencesService: PreferencesService;
  preferencesRepo: PreferencesRepository;
  historyService: NotificationHistoryService;
  historyRepo: NotificationLogRepository;
}

function buildPipeline(): Pipeline {
  const db = new Database();
  const eventBus = new EventBus();

  // Repositories
  const preferencesRepo = new PreferencesRepository(db);
  const historyRepo = new NotificationLogRepository(db);

  // Services
  const preferencesService = new PreferencesService(preferencesRepo);
  const historyService = new NotificationHistoryService(historyRepo);
  const notificationService = new NotificationService(eventBus);

  // Wire up
  notificationService.setPreferencesService(preferencesService);
  notificationService.setHistoryService(historyService);

  // Adapters — using default in-memory transports
  const emailAdapter = new EmailNotificationAdapter();
  const smsAdapter = new SmsNotificationAdapter();
  const webhookAdapter = new WebhookNotificationAdapter({ url: 'https://hooks.example.com/notify' });

  notificationService.registerAdapter(emailAdapter);
  notificationService.registerAdapter(smsAdapter);
  notificationService.registerAdapter(webhookAdapter);

  return {
    db,
    eventBus,
    notificationService,
    emailAdapter,
    smsAdapter,
    webhookAdapter,
    preferencesService,
    preferencesRepo,
    historyService,
    historyRepo,
  };
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe('Notification Pipeline — Integration', () => {
  let p: Pipeline;

  beforeEach(() => {
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
    resetNotificationLogIdCounter();
    p = buildPipeline();
  });

  // -----------------------------------------------------------------------
  // Email channel
  // -----------------------------------------------------------------------

  describe('email channel delivery', () => {
    it('should deliver email notification when email preferences are enabled', async () => {
      // Set up user preferences with email enabled
      p.preferencesService.create({
        userId: 'user-1',
        email: { enabled: true },
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      };

      await p.eventBus.emit(event);

      // Email adapter should have received the notification
      const sentEmails = p.emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(1);
      expect(sentEmails[0]!.rendered.to).toBe('alice@example.com');
      expect(sentEmails[0]!.rendered.subject).toContain('Order Confirmation');
      expect(sentEmails[0]!.rendered.html).toContain('Widget');
    });

    it('should render different templates per notification type', async () => {
      // Welcome email
      await p.eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      // Order confirmation
      await p.eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      const sentEmails = p.emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(2);
      // Welcome uses green background template
      expect(sentEmails[0]!.rendered.html).toContain('#e8f5e9');
      // Order confirmation uses white background with border
      expect(sentEmails[1]!.rendered.html).toContain('#e0e0e0');
    });
  });

  // -----------------------------------------------------------------------
  // SMS channel
  // -----------------------------------------------------------------------

  describe('SMS channel delivery', () => {
    it('should deliver SMS notification when SMS preferences are enabled', async () => {
      p.preferencesService.create({
        userId: 'user-1',
        sms: { enabled: true },
      });

      // SMS adapter validates phone numbers — the recipient from order:created
      // is an email address, so it will fail validation. Use a direct send
      // with a phone number to test SMS delivery.
      await p.notificationService.send({
        type: 'order_confirmation',
        recipient: '+15551234567',
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed.',
        metadata: { orderId: 'order-1', userId: 'user-1' },
      });

      const sentSms = p.smsAdapter.getSentMessages();
      expect(sentSms).toHaveLength(1);
      expect(sentSms[0]!.formatted.to).toBe('+15551234567');
      expect(sentSms[0]!.formatted.body).toContain('Order');
    });

    it('should format SMS body concisely per notification type', async () => {
      await p.notificationService.send({
        type: 'welcome',
        recipient: '+15551234567',
        subject: 'Welcome',
        body: 'Your account has been created.',
        metadata: { userId: 'user-1' },
      });

      const sentSms = p.smsAdapter.getSentMessages();
      expect(sentSms).toHaveLength(1);
      expect(sentSms[0]!.formatted.body).toContain('Welcome to TaskFlow Pro');
    });
  });

  // -----------------------------------------------------------------------
  // Webhook channel
  // -----------------------------------------------------------------------

  describe('webhook channel delivery', () => {
    it('should deliver webhook notification with JSON payload', async () => {
      await p.eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      const sentWebhooks = p.webhookAdapter.getSentWebhooks();
      expect(sentWebhooks).toHaveLength(1);

      const parsedBody = JSON.parse(sentWebhooks[0]!.request.body);
      expect(parsedBody.event).toBe('welcome');
      expect(parsedBody.recipient).toBe('alice@example.com');
      expect(parsedBody.subject).toBe('Welcome to TaskFlow Pro');
      expect(sentWebhooks[0]!.request.headers['Content-Type']).toBe('application/json');
    });

    it('should include webhook secret header when configured', async () => {
      // Rebuild pipeline with secret-configured webhook adapter
      const secretWebhookAdapter = new WebhookNotificationAdapter({
        url: 'https://hooks.example.com/notify',
        secret: 'my-secret-key',
      });
      // Replace the existing webhook adapter
      p.notificationService.registerAdapter(secretWebhookAdapter);

      await p.eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      const sentWebhooks = secretWebhookAdapter.getSentWebhooks();
      expect(sentWebhooks).toHaveLength(1);
      expect(sentWebhooks[0]!.request.headers['X-Webhook-Secret']).toBe('my-secret-key');
    });
  });

  // -----------------------------------------------------------------------
  // History logging
  // -----------------------------------------------------------------------

  describe('notification history logging', () => {
    it('should log all channel deliveries for a single event to history', async () => {
      await p.eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      // All three adapters (email, sms, webhook) are registered.
      // Email will succeed, SMS will fail (email address isn't a phone number),
      // webhook will succeed.
      const allLogs = p.historyService.getAll();
      expect(allLogs).toHaveLength(3);

      const emailLog = allLogs.find((l) => l.channel === 'email');
      const smsLog = allLogs.find((l) => l.channel === 'sms');
      const webhookLog = allLogs.find((l) => l.channel === 'webhook');

      expect(emailLog).toBeDefined();
      expect(emailLog!.status).toBe('sent');
      expect(emailLog!.type).toBe('welcome');

      expect(smsLog).toBeDefined();
      expect(smsLog!.status).toBe('failed');

      expect(webhookLog).toBeDefined();
      expect(webhookLog!.status).toBe('sent');
    });

    it('should record correct recipient and subject in history', async () => {
      await p.eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      const logs = p.historyService.getByRecipient('alice@example.com');
      expect(logs.length).toBeGreaterThan(0);
      expect(logs[0]!.subject).toContain('Order Confirmation');
    });

    it('should allow querying history by type', async () => {
      // Emit two different event types
      await p.eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });
      await p.eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      const welcomeLogs = p.historyService.getByType('welcome');
      const orderLogs = p.historyService.getByType('order_confirmation');

      // 3 channels per event
      expect(welcomeLogs).toHaveLength(3);
      expect(orderLogs).toHaveLength(3);
    });

    it('should log failed deliveries with error details', async () => {
      // SMS adapter will fail for an email-format recipient
      await p.notificationService.send({
        type: 'welcome',
        recipient: 'not-a-phone-number',
        subject: 'Hello',
        body: 'Test',
        metadata: { userId: 'user-1' },
      });

      const logs = p.historyService.query({ channel: 'sms', status: 'failed' });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.error).toContain('Invalid phone number');
    });
  });

  // -----------------------------------------------------------------------
  // Preferences enforcement
  // -----------------------------------------------------------------------

  describe('user preferences enforcement', () => {
    it('should skip email channel when user has email disabled', async () => {
      p.preferencesService.create({
        userId: 'user-1',
        email: { enabled: false },
        sms: { enabled: true },
        webhook: { enabled: true },
      });

      await p.eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      // Email should be suppressed
      const sentEmails = p.emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(0);

      // SMS and webhook should still fire (SMS will fail validation, but it should be attempted)
      const notifications = p.notificationService.getNotifications();
      const channels = notifications.map((n) => n.channel);
      expect(channels).not.toContain('email');
      expect(channels).toContain('sms');
      expect(channels).toContain('webhook');
    });

    it('should skip SMS channel when user has SMS disabled', async () => {
      p.preferencesService.create({
        userId: 'user-1',
        email: { enabled: true },
        sms: { enabled: false },
        webhook: { enabled: true },
      });

      await p.notificationService.send({
        type: 'order_confirmation',
        recipient: '+15551234567',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        metadata: { userId: 'user-1' },
      });

      const sentSms = p.smsAdapter.getSentMessages();
      expect(sentSms).toHaveLength(0);

      // Email will fail validation (phone number isn't an email), webhook should succeed
      const notifications = p.notificationService.getNotifications();
      const channels = notifications.map((n) => n.channel);
      expect(channels).not.toContain('sms');
    });

    it('should skip webhook channel when user has webhook disabled', async () => {
      p.preferencesService.create({
        userId: 'user-1',
        email: { enabled: true },
        sms: { enabled: true },
        webhook: { enabled: false },
      });

      await p.eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      const sentWebhooks = p.webhookAdapter.getSentWebhooks();
      expect(sentWebhooks).toHaveLength(0);

      const notifications = p.notificationService.getNotifications();
      const channels = notifications.map((n) => n.channel);
      expect(channels).not.toContain('webhook');
    });

    it('should suppress only specific categories per channel', async () => {
      p.preferencesService.create({
        userId: 'user-1',
        email: {
          enabled: true,
          categories: { welcome: false },
        },
        webhook: { enabled: true },
      });

      // Welcome should be suppressed on email
      await p.eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      const sentEmails = p.emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(0);

      // But webhook should still deliver
      const sentWebhooks = p.webhookAdapter.getSentWebhooks();
      expect(sentWebhooks).toHaveLength(1);
    });

    it('should send all channels when no preferences are set (default behavior)', async () => {
      // Do NOT create preferences — default is all enabled
      await p.eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      // All three adapters should be attempted
      const notifications = p.notificationService.getNotifications();
      expect(notifications).toHaveLength(3);

      const channels = new Set(notifications.map((n) => n.channel));
      expect(channels).toContain('email');
      expect(channels).toContain('sms');
      expect(channels).toContain('webhook');
    });

    it('should suppress all channels when everything is disabled', async () => {
      p.preferencesService.create({
        userId: 'user-1',
        email: { enabled: false },
        sms: { enabled: false },
        webhook: { enabled: false },
      });

      await p.eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      const notifications = p.notificationService.getNotifications();
      expect(notifications).toHaveLength(0);

      const sentEmails = p.emailAdapter.getSentEmails();
      const sentSms = p.smsAdapter.getSentMessages();
      const sentWebhooks = p.webhookAdapter.getSentWebhooks();
      expect(sentEmails).toHaveLength(0);
      expect(sentSms).toHaveLength(0);
      expect(sentWebhooks).toHaveLength(0);
    });
  });

  // -----------------------------------------------------------------------
  // Notification ordering
  // -----------------------------------------------------------------------

  describe('notification ordering (FIFO)', () => {
    it('should deliver notifications in the order they were sent', async () => {
      const deliveryOrder: string[] = [];
      const trackingAdapter = {
        channel: 'email' as const,
        async send(payload: { type: string; recipient: string }) {
          // Simulate variable processing time
          const delay = payload.type === 'order_confirmation' ? 30 : 5;
          await new Promise((r) => setTimeout(r, delay));
          deliveryOrder.push(payload.type);
          return { success: true, channel: 'email' as const, recipient: payload.recipient };
        },
      };

      // Replace adapters with just the tracking adapter
      const eventBus = new EventBus();
      const service = new NotificationService(eventBus);
      service.registerAdapter(trackingAdapter);

      // Fire order:created (slower) then order:status-changed (faster) concurrently
      await Promise.all([
        eventBus.emit<OrderCreatedEvent>({
          type: 'order:created',
          order: makeOrder(),
          user: makeUser(),
          timestamp: new Date(),
        }),
        eventBus.emit<OrderStatusChangedEvent>({
          type: 'order:status-changed',
          order: makeOrder({ status: 'confirmed' }),
          previousStatus: 'pending',
          newStatus: 'confirmed',
          timestamp: new Date(),
        }),
      ]);

      // Despite order_confirmation being slower, FIFO ordering must be preserved
      expect(deliveryOrder).toEqual(['order_confirmation', 'order_status_update']);
    });

    it('should preserve ordering across multiple rapid events', async () => {
      const deliveryOrder: string[] = [];
      const trackingAdapter = {
        channel: 'email' as const,
        async send(payload: { type: string; recipient: string }) {
          deliveryOrder.push(payload.type);
          return { success: true, channel: 'email' as const, recipient: payload.recipient };
        },
      };

      const eventBus = new EventBus();
      const service = new NotificationService(eventBus);
      service.registerAdapter(trackingAdapter);

      // Fire four events rapidly
      const promises = [
        eventBus.emit<UserCreatedEvent>({
          type: 'user:created',
          user: makeUser(),
          timestamp: new Date(),
        }),
        eventBus.emit<OrderCreatedEvent>({
          type: 'order:created',
          order: makeOrder(),
          user: makeUser(),
          timestamp: new Date(),
        }),
        eventBus.emit<OrderStatusChangedEvent>({
          type: 'order:status-changed',
          order: makeOrder({ status: 'confirmed' }),
          previousStatus: 'pending',
          newStatus: 'confirmed',
          timestamp: new Date(),
        }),
        eventBus.emit<UserUpdatedEvent>({
          type: 'user:updated',
          user: makeUser(),
          changes: ['name'],
          timestamp: new Date(),
        }),
      ];

      await Promise.all(promises);

      expect(deliveryOrder).toEqual([
        'welcome',
        'order_confirmation',
        'order_status_update',
        'account_updated',
      ]);
    });
  });

  // -----------------------------------------------------------------------
  // Full end-to-end scenarios
  // -----------------------------------------------------------------------

  describe('end-to-end scenarios', () => {
    it('should handle a complete order lifecycle through all channels', async () => {
      const user = makeUser();
      const order = makeOrder();

      // 1. User created → welcome notification
      await p.eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user,
        timestamp: new Date(),
      });

      // 2. Order created → order confirmation
      await p.eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order,
        user,
        timestamp: new Date(),
      });

      // 3. Order shipped → status update
      await p.eventBus.emit<OrderStatusChangedEvent>({
        type: 'order:status-changed',
        order: { ...order, status: 'shipped' },
        previousStatus: 'pending',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      // 3 events × 3 channels = 9 total notification attempts
      const notifications = p.notificationService.getNotifications();
      expect(notifications).toHaveLength(9);

      // History should also have 9 entries
      const historyCount = p.historyService.count();
      expect(historyCount).toBe(9);

      // Verify the types appear in order
      const types = notifications.map((n) => n.type);
      const welcomeIndices = types.reduce<number[]>((acc, t, i) => (t === 'welcome' ? [...acc, i] : acc), []);
      const orderConfirmIndices = types.reduce<number[]>((acc, t, i) => (t === 'order_confirmation' ? [...acc, i] : acc), []);
      const statusUpdateIndices = types.reduce<number[]>((acc, t, i) => (t === 'order_status_update' ? [...acc, i] : acc), []);

      // All welcome notifications come before order confirmations
      expect(Math.max(...welcomeIndices)).toBeLessThan(Math.min(...orderConfirmIndices));
      // All order confirmations come before status updates
      expect(Math.max(...orderConfirmIndices)).toBeLessThan(Math.min(...statusUpdateIndices));
    });

    it('should handle mixed preferences across channels in a multi-event flow', async () => {
      // User wants email for everything, SMS only for orders, no webhooks
      p.preferencesService.create({
        userId: 'user-1',
        email: { enabled: true },
        sms: { enabled: true, categories: { welcome: false, account_updated: false } },
        webhook: { enabled: false },
      });

      // Welcome event
      await p.eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      // Order event
      await p.eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      const notifications = p.notificationService.getNotifications();

      // Welcome: email only (sms welcome disabled, webhook disabled)
      const welcomeNotifs = notifications.filter((n) => n.type === 'welcome');
      expect(welcomeNotifs).toHaveLength(1);
      expect(welcomeNotifs[0]!.channel).toBe('email');

      // Order: email + sms (webhook disabled)
      const orderNotifs = notifications.filter((n) => n.type === 'order_confirmation');
      expect(orderNotifs).toHaveLength(2);
      const orderChannels = new Set(orderNotifs.map((n) => n.channel));
      expect(orderChannels).toContain('email');
      expect(orderChannels).toContain('sms');
      expect(orderChannels).not.toContain('webhook');
    });

    it('should correlate history entries with notification records', async () => {
      await p.eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      const notifications = p.notificationService.getNotifications();
      const historyLogs = p.historyService.getAll();

      // Each notification should have a corresponding history entry
      expect(historyLogs).toHaveLength(notifications.length);

      for (const notif of notifications) {
        const log = historyLogs.find((l) => l.notificationId === notif.id);
        expect(log).toBeDefined();
        expect(log!.channel).toBe(notif.channel);
        expect(log!.type).toBe(notif.type);
        expect(log!.recipient).toBe(notif.recipient);
        expect(log!.status).toBe(notif.success ? 'sent' : 'failed');
      }
    });

    it('should handle account update notifications through the pipeline', async () => {
      await p.eventBus.emit<UserUpdatedEvent>({
        type: 'user:updated',
        user: makeUser(),
        changes: ['email', 'name'],
        timestamp: new Date(),
      });

      const notifications = p.notificationService.getNotifications();
      expect(notifications.length).toBeGreaterThan(0);

      const emailNotif = notifications.find((n) => n.channel === 'email');
      expect(emailNotif).toBeDefined();
      expect(emailNotif!.type).toBe('account_updated');
      expect(emailNotif!.body).toContain('email');
      expect(emailNotif!.body).toContain('name');
    });
  });
});

