+import type { Order } from '../../src/models/order.js';
+import type { SentEmailRecord } from '../../src/adapters/email.adapter.js';
+import type { SentSmsRecord } from '../../src/adapters/sms.adapter.js';
+import type { SentWebhookRecord } from '../../src/adapters/webhook.adapter.js';
