+  notificationService.registerAdapter(webhookAdapter);
+
+  return {
+    db,
+    eventBus,
+    notificationService,
+    emailAdapter,
+    smsAdapter,
+    webhookAdapter,
+    preferencesService,
+    preferencesRepo,
+    historyService,
